import React, { Component } from 'react';

class Footer extends Component {
  render() {
    return (
      <div>
        <footer className="footer bg-light text-center text-muted py-3 mt-auto shadow-sm">
          <div>
            <p className="mb-1 fw-semibold">
              © 2025 LifeGift - Urgent Organ and Blood Donation Matching
            </p>
            <p className="mb-0 small">
              Developed by Team LifeGift | Department of CSE, University of Information Technology & Sciences (UITS)
            </p>
            <p className="small mb-0">
              Guided by <strong>Eng. Md. Safaet Hossain</strong>, Associate Professor & Director, IQAC
            </p>
          </div>
        </footer>
      </div>
    );
  }
}

export default Footer;
